36	interface ApiFetchOptions extends Omit<RequestInit, "body"> {
37	  params?: Record<string, string | number | undefined>;
38	  body?: unknown;
39	}
40	
41	function buildUrl(baseUrl: string, params?: Record<string, string | number | undefined>): string {
42	  if (!params) return baseUrl;
43	
44	  const searchParams = new URLSearchParams();
45	  for (const [key, value] of Object.entries(params)) {
46	    if (value !== undefined) {
47	      searchParams.set(key, String(value));
48	    }
49	  }
50	
51	  const qs = searchParams.toString();
52	  if (qs) {
53	    return baseUrl + (baseUrl.includes("?") ? "&" : "?") + qs;
54	  }
55	  return baseUrl;
56	}
57	
58	export async function apiFetch<T = unknown>(
59	  url: string,
60	  options: ApiFetchOptions = {},
61	): Promise<T> {
62	  const token = getToken();
63	  const isDemo = token?.startsWith("demo-token-");
64	
65	  const headers = new Headers(options.headers);
66	
67	  // Only set Content-Type when there is a body and it's not already set
68	  if (options.body && !headers.has("Content-Type")) {
69	    headers.set("Content-Type", "application/json");
70	  }
71	
72	  if (token) {
73	    headers.set("Authorization", `Bearer ${token}`);
74	  }
75	
76	  const { params, ...fetchOptions } = options;
77	  const finalUrl = buildUrl(url, params);
78	
79	  // Auto-serialize object bodies to JSON
80	  const body =
81	    options.body && typeof options.body === "object" && !(options.body instanceof FormData) && !(options.body instanceof URLSearchParams) && !(options.body instanceof Blob) && !(options.body instanceof ArrayBuffer) && !(options.body instanceof ReadableStream)
82	      ? JSON.stringify(options.body)
83	      : options.body;
84	
85	  const response = await fetch(finalUrl, {
86	    ...fetchOptions,
87	    body: body as BodyInit | undefined,
88	    headers,
89	  });
90	
91	  if (response.status === 401 && !isDemo) {
92	    clearToken();
93	    throw new ApiError(401, "Unauthorized");
94	  }
95	
96	  if (!response.ok) {
97	    // Demo mode: return empty data instead of throwing
98	    if (isDemo) {
99	      // List endpoints (with page param) → empty paginated; detail endpoints → null
100	      if (options.params?.page !== undefined) {
101	        return { data: [], pagination: { page: 1, pageSize: 20, total: 0, totalPages: 0 } } as T;
102	      }
103	      return null as T;
104	    }
105	
106	    let message = `Request failed with status ${response.status}`;
107	    try {
108	      const responseBody = await response.json();
109	      if (responseBody.error) message = responseBody.error;
110	      if (responseBody.message) message = responseBody.message;
111	    } catch {
112	      // ignore parse errors
113	    }
114	    throw new ApiError(response.status, message);
115	  }
116	
117	  // Handle 204 No Content
118	  if (response.status === 204) {
119	    return undefined as T;
120	  }
121	
122	  return response.json() as Promise<T>;
123	}
124	
125	export { getToken, TOKEN_KEY };
